#define DEFAULT_ORDER 508

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    bool is_leaf;
    int num_keys;
} knode;

kernel void findK(
    long maxheight,
    const knode *knodes,
    long knodes_elem,
    const record *records,
    long *currKnode,
    long *offset,
    const int *keys,
    record *ans)
{
    int bid = get_global_id(0) / get_local_size(0);
    int thid = get_local_id(0);
    int count = get_global_size(0) / get_local_size(0);
    int threadsPerBlock = get_local_size(0);

    if (bid >= count) return;

    long local_currKnode = currKnode[bid];
    long local_offset = offset[bid];
    int local_key = keys[bid];

    for (long i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[local_currKnode].keys[thid] <= local_key) && 
                (knodes[local_currKnode].keys[thid + 1] > local_key)) {
                if (knodes[local_offset].indices[thid] < knodes_elem) {
                    local_offset = knodes[local_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            local_currKnode = local_offset;
        }
    }

    if (thid < threadsPerBlock) {
        if (knodes[local_currKnode].keys[thid] == local_key) {
            ans[bid].value = records[knodes[local_currKnode].indices[thid]].value;
        }
    }
}

